33:/**
34: * Build a minimal StartupContext that captures and fires events.
35: */
36:function buildCtx(): {
37:  ctx: StartupContext;
38:  fire: (event: string, ...args: unknown[]) => Promise<void>;
39:} {
40:  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
41:  const ctx: StartupContext = {
42:    on(event, handler) {
43:      const list = handlers.get(event) ?? [];
44:      list.push(handler);
45:      handlers.set(event, list);
46:    },
47:  };
48:  async function fire(event: string, ...args: unknown[]): Promise<void> {
49:    for (const h of handlers.get(event) ?? []) {
50:      await h(...args);
51:    }
52:  }
53:  return { ctx, fire };
54:}
56:/**
57: * Full integration fixture: starts Stacks (memory), Clerk, Fabricator,
58: * and Spider. Returns handles to each API plus mock animator controls.
59: */
60:function buildFixture(
61:  guildConfig: Partial<GuildConfig> = {},
62:  initialSessionOutcome: { status: 'completed' | 'failed'; error?: string; output?: string } = { status: 'completed' },
63:): {
64:  stacks: StacksApi;
65:  clerk: ClerkApi;
66:  fabricator: FabricatorApi;
67:  spider: SpiderApi;
68:  memBackend: InstanceType<typeof MemoryBackend>;
69:  fire: (event: string, ...args: unknown[]) => Promise<void>;
70:  summonCalls: SummonRequest[];
71:  setSessionOutcome: (outcome: { status: 'completed' | 'failed'; error?: string; output?: string }) => void;
72:} {
73:  const memBackend = new MemoryBackend();
74:  const stacksPlugin = createStacksApparatus(memBackend);
75:  const clerkPlugin = createClerk();
76:  const fabricatorPlugin = createFabricator();
77:  const spiderPlugin = createSpider();
79:  if (!('apparatus' in stacksPlugin)) throw new Error('stacks must be apparatus');
80:  if (!('apparatus' in clerkPlugin)) throw new Error('clerk must be apparatus');
81:  if (!('apparatus' in fabricatorPlugin)) throw new Error('fabricator must be apparatus');
82:  if (!('apparatus' in spiderPlugin)) throw new Error('spider must be apparatus');
84:  const stacksApparatus = stacksPlugin.apparatus;
85:  const clerkApparatus = clerkPlugin.apparatus;
86:  const fabricatorApparatus = fabricatorPlugin.apparatus;
87:  const spiderApparatus = spiderPlugin.apparatus;
89:  const apparatusMap = new Map<string, unknown>();
91:  const fakeGuildConfig: GuildConfig = {
92:    name: 'test-guild',
93:    nexus: '0.0.0',
94:    plugins: [],
95:    ...guildConfig,
96:  };
98:  const fakeGuild: Guild = {
99:    home: '/tmp/test-guild',
100:    apparatus<T>(name: string): T {
101:      const api = apparatusMap.get(name);
102:      if (!api) throw new Error(`Apparatus "${name}" not found`);
103:      return api as T;
104:    },
105:    config<T>(_pluginId: string): T { return {} as T; },
106:    writeConfig() {},
107:    guildConfig() { return fakeGuildConfig; },
108:    kits(): LoadedKit[] { return []; },
109:    apparatuses(): LoadedApparatus[] { return []; },
110:  };
112:  setGuild(fakeGuild);
114:  // Start stacks with memory backend
115:  const noopCtx = { on: () => {} };
116:  stacksApparatus.start(noopCtx);
117:  const stacks = stacksApparatus.provides as StacksApi;
118:  apparatusMap.set('stacks', stacks);
120:  // Manually ensure all books the Spider and Clerk need
121:  memBackend.ensureBook({ ownerId: 'clerk', book: 'writs' }, {
122:    indexes: ['status', 'type', 'createdAt', ['status', 'type'], ['status', 'createdAt']],
123:  });
124:  memBackend.ensureBook({ ownerId: 'spider', book: 'rigs' }, {
125:    indexes: ['status', 'writId', ['status', 'writId'], 'createdAt'],
126:  });
127:  memBackend.ensureBook({ ownerId: 'animator', book: 'sessions' }, {
128:    indexes: ['startedAt', 'status'],
129:  });
131:  // Mock animator — captures summon() calls and writes session docs to Stacks.
132:  // The session record is written eagerly (synchronous put, fire-and-forget)
133:  // so the Spider's collect step finds it on the next crawl() call. Engines
134:  // no longer await handle.result — they return immediately with handle.sessionId.
135:  let currentSessionOutcome = initialSessionOutcome;
136:  const summonCalls: SummonRequest[] = [];
137:  const mockAnimatorApi: AnimatorApi = {
138:    summon(request: SummonRequest): AnimateHandle {
139:      summonCalls.push(request);
140:      const sessionId = generateId('ses', 4);
141:      const startedAt = new Date().toISOString();
142:      const outcome = currentSessionOutcome;
144:      const sessBook = stacks.book<SessionDoc>('animator', 'sessions');
145:      const endedAt = new Date().toISOString();
146:      const doc: SessionDoc = {
147:        id: sessionId,
148:        status: outcome.status,
149:        startedAt,
150:        endedAt,
151:        durationMs: 0,
152:        provider: 'mock',
153:        exitCode: outcome.status === 'completed' ? 0 : 1,
154:        ...(outcome.error ? { error: outcome.error } : {}),
155:        ...(outcome.output !== undefined ? { output: outcome.output } : {}),
156:        metadata: request.metadata,
157:      };
158:      // Write eagerly — fire and forget. The in-memory backend is sync.
159:      void sessBook.put(doc);
161:      const result = Promise.resolve({
162:        id: sessionId,
163:        status: outcome.status,
164:        startedAt,
165:        endedAt,
166:        durationMs: 0,
167:        provider: 'mock',
168:        exitCode: outcome.status === 'completed' ? 0 : 1,
169:        ...(outcome.error ? { error: outcome.error } : {}),
170:        ...(outcome.output !== undefined ? { output: outcome.output } : {}),
171:        metadata: request.metadata,
172:      } as SessionResult);
174:      async function* emptyChunks(): AsyncIterable<SessionChunk> {}
175:      return { sessionId, chunks: emptyChunks(), result };
176:    },
177:    animate(): AnimateHandle {
178:      throw new Error('animate() not used in Spider tests');
179:    },
180:  };
181:  apparatusMap.set('animator', mockAnimatorApi);
183:  // Start clerk
184:  clerkApparatus.start(noopCtx);
185:  const clerk = clerkApparatus.provides as ClerkApi;
186:  apparatusMap.set('clerk', clerk);
188:  // Start fabricator with its own ctx so we can fire events
189:  const { ctx: fabricatorCtx, fire } = buildCtx();
190:  fabricatorApparatus.start(fabricatorCtx);
191:  const fabricator = fabricatorApparatus.provides as FabricatorApi;
192:  apparatusMap.set('fabricator', fabricator);
194:  // Start spider
195:  spiderApparatus.start(noopCtx);
196:  const spider = spiderApparatus.provides as SpiderApi;
197:  apparatusMap.set('spider', spider);
199:  // Simulate plugin:initialized for the Spider so the Fabricator scans
200:  // its supportKit and picks up the five engine designs.
201:  const spiderLoaded: LoadedApparatus = {
202:    packageName: '@shardworks/spider-apparatus',
203:    id: 'spider',
204:    version: '0.0.0',
205:    apparatus: spiderApparatus,
206:  };
207:  // Fire synchronously — fabricator's handler is sync
208:  void fire('plugin:initialized', spiderLoaded);
210:  return {
211:    stacks, clerk, fabricator, spider, memBackend, fire,
212:    summonCalls,
213:    setSessionOutcome(outcome: { status: 'completed' | 'failed'; error?: string; output?: string }) {
214:      currentSessionOutcome = outcome;
215:    },
216:  };
217:}
