1:/**
2: * Seal engine — clockwork.
3: *
4: * Seals the draft binding via the Scriptorium. Reads the draft branch
5: * from context.upstream['draft'] (the DraftYields from the draft engine).
6: * Returns SealYields with the sealed commit info.
7: */
9:import { guild } from '@shardworks/nexus-core';
10:import type { EngineDesign } from '@shardworks/fabricator-apparatus';
11:import type { ScriptoriumApi } from '@shardworks/codexes-apparatus';
12:import type { DraftYields, SealYields } from '../types.ts';
14:const sealEngine: EngineDesign = {
15:  id: 'seal',
17:  async run(_givens, context) {
18:    const scriptorium = guild().apparatus<ScriptoriumApi>('codexes');
19:    const draftYields = context.upstream['draft'] as DraftYields | undefined;
21:    if (!draftYields) {
22:      throw new Error('Seal engine requires draft yields in context.upstream but none found.');
23:    }
25:    const result = await scriptorium.seal({
26:      codexName: draftYields.codexName,
27:      sourceBranch: draftYields.branch,
28:    });
30:    const yields: SealYields = {
31:      sealedCommit: result.sealedCommit,
32:      strategy: result.strategy,
33:      retries: result.retries,
34:      inscriptionsSealed: result.inscriptionsSealed,
35:    };
37:    return { status: 'completed', yields };
38:  },
39:};
41:export default sealEngine;

