1:/**
2: * crawl-continual tool — runs the crawl loop continuously.
3: *
4: * Polls crawl() on a configurable interval. By default the loop runs
5: * indefinitely; pass a positive maxIdleCycles to enable auto-stop after
6: * that many consecutive idle cycles.
7: */
9:import { z } from 'zod';
10:import { guild } from '@shardworks/nexus-core';
11:import { tool } from '@shardworks/tools-apparatus';
12:import type { SpiderApi, SpiderConfig } from '../types.ts';
14:export default tool({
15:  name: 'crawl-continual',
16:  description: "Run the Spider's crawl loop continuously",
17:  instructions:
18:    'Polls crawl() in a loop, sleeping between steps when idle. ' +
19:    'By default the loop runs indefinitely. Pass a positive maxIdleCycles ' +
20:    'to stop after that many consecutive idle cycles. ' +
21:    'Returns a summary of all actions taken.',
22:  params: {
23:    maxIdleCycles: z
24:      .number()
25:      .optional()
26:      .default(0)
27:      .describe(
28:        'Max consecutive idle cycles before stopping. Pass a positive number to enable auto-stop (default: runs indefinitely)',
29:      ),
30:    pollIntervalMs: z
31:      .number()
32:      .optional()
33:      .describe(
34:        'Override the configured poll interval in milliseconds',
35:      ),
36:  },
37:  permission: 'spider:write',
38:  handler: async (params) => {
39:    const g = guild();
40:    const spider = g.apparatus<SpiderApi>('spider');
41:    const config = g.guildConfig().spider ?? {} as SpiderConfig;
42:    const intervalMs = params.pollIntervalMs ?? config.pollIntervalMs ?? 5000;
43:    const maxIdle = params.maxIdleCycles;
45:    const actions: unknown[] = [];
46:    let idleCount = 0;
48:    while (maxIdle === 0 || idleCount < maxIdle) {
49:      let result: Awaited<ReturnType<typeof spider.crawl>>;
50:      try {
51:        result = await spider.crawl();
52:      } catch (err) {
53:        console.error('[crawl-continual] crawl() error:', err instanceof Error ? err.message : String(err));
54:        idleCount++;
55:        await new Promise<void>((resolve) => setTimeout(resolve, intervalMs));
56:        continue;
57:      }
58:      if (result === null) {
59:        idleCount++;
60:        await new Promise<void>((resolve) => setTimeout(resolve, intervalMs));
61:      } else {
62:        idleCount = 0;
63:        actions.push(result);
64:      }
65:    }
67:    return { actions, totalActions: actions.length };
68:  },
69:});

