1:/**
2: * CDC registry — handler registration, event buffering, and coalescing.
3: *
4: * Two-phase execution model:
5: * - Phase 1 (failOnError: true):  runs INSIDE the transaction
6: * - Phase 2 (failOnError: false): runs AFTER commit with coalesced events
7: *
8: * See: docs/specification.md (stacks § CDC)
9: */
11:import type { BookEntry, ChangeEvent, ChangeHandler, WatchOptions } from './types.ts';
13:// ── Registry entry ────────────────────────────────────────────────────
15:interface WatcherEntry {
16:  handler: ChangeHandler;
17:  failOnError: boolean;
18:}
20:// ── Event buffer entry (raw, pre-coalesce) ────────────────────────────
22:export interface BufferedEvent {
23:  ref: string;          // "${ownerId}/${bookName}"
24:  ownerId: string;
25:  book: string;
26:  docId: string;
27:  type: 'create' | 'update' | 'delete';
28:  entry?: BookEntry;    // present for create/update
29:  prev?: BookEntry;     // present for update/delete
30:}
32:// ── Coalescing state machine ──────────────────────────────────────────
34:interface CoalesceState {
35:  ownerId: string;
36:  book: string;
37:  docId: string;
38:  /** The first event's type — needed for coalescing rules. */
39:  firstType: 'create' | 'update' | 'delete';
40:  /** The most recent event's type. */
41:  lastType: 'create' | 'update' | 'delete';
42:  /** Pre-transaction state (prev from first event). */
43:  prev?: BookEntry;
44:  /** Final state (entry from last event). */
45:  entry?: BookEntry;
46:}
48:/**
49: * Coalesce buffered events per-document.
50: *
51: * Rules:
52: *   create                    → create (final state)
53: *   create → update(s)        → create (final state)
54: *   create → delete           → (no event)
55: *   update(s)                 → update (first prev, final state)
56: *   update(s) → delete        → delete (first prev)
57: *   delete                    → delete (prev)
58: */
59:export function coalesceEvents(buffer: BufferedEvent[]): ChangeEvent<BookEntry>[] {
60:  const states = new Map<string, CoalesceState>();
62:  for (const event of buffer) {
63:    const key = `${event.ref}:${event.docId}`;
64:    const existing = states.get(key);
66:    if (!existing) {
67:      states.set(key, {
68:        ownerId: event.ownerId,
69:        book: event.book,
70:        docId: event.docId,
71:        firstType: event.type,
72:        lastType: event.type,
73:        prev: event.prev,
74:        entry: event.entry,
75:      });
76:    } else {
77:      existing.lastType = event.type;
78:      if (event.entry) existing.entry = event.entry;
79:      // prev stays as the first event's prev (pre-transaction state)
80:    }
81:  }
83:  const events: ChangeEvent<BookEntry>[] = [];
85:  for (const state of states.values()) {
86:    if (state.firstType === 'create' && state.lastType === 'delete') {
87:      // create → delete: no event (document never existed from observer's perspective)
88:      continue;
89:    }
91:    if (state.firstType === 'create') {
92:      // create (possibly followed by updates): coalesces to create with final state
93:      events.push({
94:        type: 'create',
95:        ownerId: state.ownerId,
96:        book: state.book,
97:        entry: state.entry!,
98:      });
99:    } else if (state.lastType === 'delete') {
100:      // update(s) → delete: coalesces to delete with original prev
101:      events.push({
102:        type: 'delete',
103:        ownerId: state.ownerId,
104:        book: state.book,
105:        id: state.docId,
106:        prev: state.prev!,
107:      });
108:    } else {
109:      // update(s): coalesces to single update with first prev, final entry
110:      events.push({
111:        type: 'update',
112:        ownerId: state.ownerId,
113:        book: state.book,
114:        entry: state.entry!,
115:        prev: state.prev!,
116:      });
117:    }
118:  }
120:  return events;
121:}
123:// ── CDC Registry ──────────────────────────────────────────────────────
125:export class CdcRegistry {
126:  private readonly watchers = new Map<string, WatcherEntry[]>();
127:  private locked = false;
129:  /**
130:   * Register a CDC handler for a book.
131:   * Must be called before any writes (enforced by `locked` flag).
132:   */
133:  watch(
134:    ownerId: string,
135:    bookName: string,
136:    handler: ChangeHandler,
137:    options?: WatchOptions,
138:  ): void {
139:    if (this.locked) {
140:      throw new Error(
141:        `[stacks] watch() called after writes have started. ` +
142:        `Handlers must be registered during apparatus startup.`,
143:      );
144:    }
146:    const key = `${ownerId}/${bookName}`;
147:    let entries = this.watchers.get(key);
148:    if (!entries) {
149:      entries = [];
150:      this.watchers.set(key, entries);
151:    }
152:    entries.push({
153:      handler,
154:      failOnError: options?.failOnError ?? true,
155:    });
156:  }
158:  /** Mark the registry as locked — called on first write. */
159:  lock(): void {
160:    this.locked = true;
161:  }
163:  /** Check if any handlers are registered for a book (controls pre-read). */
164:  hasWatchers(ownerId: string, bookName: string): boolean {
165:    const key = `${ownerId}/${bookName}`;
166:    const entries = this.watchers.get(key);
167:    return entries !== undefined && entries.length > 0;
168:  }
170:  /** Get Phase 1 handlers (failOnError: true) for a book. */
171:  getPhase1Handlers(ownerId: string, bookName: string): WatcherEntry[] {
172:    const key = `${ownerId}/${bookName}`;
173:    return (this.watchers.get(key) ?? []).filter((e) => e.failOnError);
174:  }
176:  /** Get Phase 2 handlers (failOnError: false) for a book. */
177:  getPhase2Handlers(ownerId: string, bookName: string): WatcherEntry[] {
178:    const key = `${ownerId}/${bookName}`;
179:    return (this.watchers.get(key) ?? []).filter((e) => !e.failOnError);
180:  }
182:  /**
183:   * Fire Phase 1 handlers for a single event. Throws on handler error
184:   * (caller is responsible for rolling back the transaction).
185:   */
186:  async firePhase1(
187:    ownerId: string,
188:    bookName: string,
189:    event: ChangeEvent<BookEntry>,
190:  ): Promise<void> {
191:    for (const entry of this.getPhase1Handlers(ownerId, bookName)) {
192:      await entry.handler(event);
193:    }
194:  }
196:  /**
197:   * Fire Phase 2 handlers for coalesced events. Errors are logged, not thrown.
198:   */
199:  async firePhase2(events: ChangeEvent<BookEntry>[]): Promise<void> {
200:    for (const event of events) {
201:      const key = `${event.ownerId}/${event.book}`;
202:      const handlers = (this.watchers.get(key) ?? []).filter((e) => !e.failOnError);
204:      for (const entry of handlers) {
205:        try {
206:          await entry.handler(event);
207:        } catch (err) {
208:          const msg = err instanceof Error ? err.message : String(err);
209:          console.warn(`[stacks] Phase 2 handler error (${key}): ${msg}`);
210:        }
211:      }
212:    }
213:  }
214:}

