1:/**
2: * Clerk public types.
3: *
4: * All types exported from @shardworks/clerk-apparatus.
5: */
7:// ── Writ status ──────────────────────────────────────────────────────
9:/**
10: * A writ's position in its lifecycle.
11: *
12: * Transitions:
13: *   ready → active (accept)
14: *   active → completed (complete)
15: *   active → failed (fail)
16: *   ready | active → cancelled (cancel)
17: *
18: * completed, failed, cancelled are terminal — no further transitions.
19: */
20:export type WritStatus = 'ready' | 'active' | 'completed' | 'failed' | 'cancelled';
22:// ── Documents ────────────────────────────────────────────────────────
24:/**
25: * A writ document as stored in The Stacks.
26: */
27:export interface WritDoc {
28:  /** Index signature required to satisfy BookEntry constraint. */
29:  [key: string]: unknown;
30:  /** Unique writ id (`w-{base36_timestamp}{hex_random}`). Sortable by creation time. */
31:  id: string;
32:  /** Writ type — must be a type declared in guild config, or a built-in type. */
33:  type: string;
34:  /** Current lifecycle status. */
35:  status: WritStatus;
36:  /** Short human-readable title. */
37:  title: string;
38:  /** Detail text. */
39:  body: string;
40:  /** Target codex name. */
41:  codex?: string;
42:  /** ISO timestamp when the writ was created. */
43:  createdAt: string;
44:  /** ISO timestamp of the last mutation. */
45:  updatedAt: string;
46:  /** ISO timestamp when the writ was accepted (transitioned to active). */
47:  acceptedAt?: string;
48:  /** ISO timestamp when the writ reached a terminal state. */
49:  resolvedAt?: string;
50:  /** Summary of how the writ resolved (set on any terminal transition). */
51:  resolution?: string;
52:}
54:// ── Requests ─────────────────────────────────────────────────────────
56:/**
57: * Request to post a new commission (create a writ).
58: */
59:export interface PostCommissionRequest {
60:  /**
61:   * Writ type. Defaults to the guild's configured defaultType, or "mandate"
62:   * if no default is configured. Must be a valid declared type.
63:   */
64:  type?: string;
65:  /** Short human-readable title describing the work. */
66:  title: string;
67:  /** Detail text. */
68:  body: string;
69:  /** Optional target codex name. */
70:  codex?: string;
71:}
73:// ── Filters ──────────────────────────────────────────────────────────
75:/**
76: * Filters for listing writs.
77: */
78:export interface WritFilters {
79:  /** Filter by status. */
80:  status?: WritStatus;
81:  /** Filter by writ type. */
82:  type?: string;
83:  /** Maximum number of results (default: 20). */
84:  limit?: number;
85:  /** Number of results to skip. */
86:  offset?: number;
87:}
89:// ── Configuration ───────────────────────────────────────────────
91:/**
92: * A writ type entry declared in clerk config.
93: */
94:export interface WritTypeEntry {
95:  /** The writ type name (e.g. "mandate", "task", "bug"). */
96:  name: string;
97:  /** Optional human-readable description of this writ type. */
98:  description?: string;
99:}
101:/**
102: * Clerk apparatus configuration — lives under the `clerk` key in guild.json.
103: */
104:export interface ClerkConfig {
105:  /** Additional writ type declarations. The built-in type "mandate" is always valid. */
106:  writTypes?: WritTypeEntry[];
107:  /** Default writ type when commission-post is called without a type (default: "mandate"). */
108:  defaultType?: string;
109:}
111:// Augment GuildConfig so `guild().guildConfig().clerk` is typed without
112:// requiring a manual type parameter at the call site.
113:declare module '@shardworks/nexus-core' {
114:  interface GuildConfig {
115:    clerk?: ClerkConfig;
116:  }
117:}
119:// ── Link documents ───────────────────────────────────────────────────
121:/**
122: * A link document as stored in The Stacks (clerk/links book).
123: */
124:export interface WritLinkDoc {
125:  /** Index signature required to satisfy BookEntry constraint. */
126:  [key: string]: unknown;
127:  /** Deterministic composite key: `{sourceId}:{targetId}:{type}`. */
128:  id: string;
129:  /** The writ that is the origin of this relationship. */
130:  sourceId: string;
131:  /** The writ that is the target of this relationship. */
132:  targetId: string;
133:  /** Relationship type — an open string (e.g. "fixes", "retries", "supersedes", "duplicates"). */
134:  type: string;
135:  /** ISO timestamp when the link was created. */
136:  createdAt: string;
137:}
139:/**
140: * Result of querying links for a writ — both directions in one response.
141: */
142:export interface WritLinks {
143:  /** Links where this writ is the source (this writ → other writ). */
144:  outbound: WritLinkDoc[];
145:  /** Links where this writ is the target (other writ → this writ). */
146:  inbound: WritLinkDoc[];
147:}
149:// ── API ──────────────────────────────────────────────────────────────
151:/**
152: * The Clerk's runtime API — retrieved via guild().apparatus<ClerkApi>('clerk').
153: */
154:export interface ClerkApi {
155:  /**
156:   * Post a new commission, creating a writ in 'ready' status.
157:   * Validates the writ type against declared types in guild config.
158:   */
159:  post(request: PostCommissionRequest): Promise<WritDoc>;
161:  /**
162:   * Show a writ by id. Throws if not found.
163:   */
164:  show(id: string): Promise<WritDoc>;
166:  /**
167:   * List writs with optional filters, ordered by createdAt descending.
168:   */
169:  list(filters?: WritFilters): Promise<WritDoc[]>;
171:  /**
172:   * Count writs matching optional filters.
173:   */
174:  count(filters?: WritFilters): Promise<number>;
176:  /**
177:   * Transition a writ to a new status, optionally setting additional fields.
178:   * Validates that the transition is legal.
179:   */
180:  transition(id: string, to: WritStatus, fields?: Partial<WritDoc>): Promise<WritDoc>;
182:  /**
183:   * Create a typed directional link from one writ to another.
184:   * Both writs must exist. Self-links are rejected. Idempotent — returns
185:   * the existing link if the (sourceId, targetId, type) triple already exists.
186:   */
187:  link(sourceId: string, targetId: string, type: string): Promise<WritLinkDoc>;
189:  /**
190:   * Query all links for a writ — both outbound (this writ is the source)
191:   * and inbound (this writ is the target).
192:   */
193:  links(writId: string): Promise<WritLinks>;
195:  /**
196:   * Remove a link. Idempotent — no error if the link does not exist.
197:   */
198:  unlink(sourceId: string, targetId: string, type: string): Promise<void>;
199:}

